import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    scores = np.zeros(len(unvisited_customers))
    for i, customer_pos in enumerate(unvisited_customers):
        direct_time = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + direct_time
        window_start, window_end = time_windows[i]

        # Calculate time window proximity score
        if arrival_time < window_start:
            score = (window_start - arrival_time)  # Scaled penalty for arriving early
        elif arrival_time > window_end:
            score = (arrival_time - window_end) * 10  # Higher penalty for arriving late
        else:
            score = 0  # No penalty if within the time window

        # Adaptive truck proximity adjustment
        for other_pos in all_truck_pos:
            if not np.array_equal(other_pos, cur_truck_pos):
                other_time_to_customer = travel_time(other_pos, customer_pos)
                distance_influence = np.linalg.norm(other_pos - customer_pos) / (np.linalg.norm(cur_truck_pos - customer_pos) + 0.01)
                if other_time_to_customer < direct_time:
                    score += (direct_time - other_time_to_customer) * distance_influence * 5

        scores[i] = score

    best_node = np.argmin(scores)
    return best_node

