import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    travel_times = np.array([euclidean_distance(cur_truck_pos, customer) / truck_speed for customer in unvisited_customers])
    arrival_times = current_time + travel_times

    time_cost = np.zeros(len(unvisited_customers))
    for i, (start, end) in enumerate(time_windows):
        if arrival_times[i] < start:
            time_cost[i] = (start - arrival_times[i])  # Waiting time until the window opens
        elif arrival_times[i] > end:
            time_cost[i] = (arrival_times[i] - end) * 10  # High penalty if outside the window
        else:
            time_cost[i] = 0  # No cost if within the window

    penalty_other_trucks = np.zeros(len(unvisited_customers))
    for pos in all_truck_pos:
        if np.array_equal(pos, cur_truck_pos):
            continue
        other_travel_times = np.array([euclidean_distance(pos, customer) / truck_speed for customer in unvisited_customers])
        for i in range(len(unvisited_customers)):
            if other_travel_times[i] < travel_times[i]:  # Other truck can get there sooner
                penalty_other_trucks[i] += (travel_times[i] - other_travel_times[i])

    overall_cost = travel_times + time_cost + penalty_other_trucks
    best_node = np.argmin(overall_cost)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    # Calculate travel times to each unvisited customer for current truck
    travel_times = np.array([euclidean_distance(cur_truck_pos, customer) / truck_speed for customer in unvisited_customers])
    arrival_times = current_time + travel_times

    # Calculate time cost with respect to time windows
    time_cost = np.zeros(len(unvisited_customers))
    for i, (start, end) in enumerate(time_windows):
        if arrival_times[i] < start:
            time_cost[i] = (start - arrival_times[i])  # Wait time penalty
        elif arrival_times[i] > end:
            time_cost[i] = (arrival_times[i] - end) * 10  # Miss window penalty
        else:
            time_cost[i] = 0  # No penalty if within the window

    # Consider the plans of other trucks to reduce overlap and collision of routes
    collaborative_cost = np.zeros(len(unvisited_customers))
    for truck_pos in all_truck_pos:
        if np.array_equal(truck_pos, cur_truck_pos):
            continue
        their_travel_times = np.array([euclidean_distance(truck_pos, customer) / truck_speed for customer in unvisited_customers])
        their_arrival_times = current_time + their_travel_times
        for i in range(len(unvisited_customers)):
            # Incentivize trucks to not choose the same customer if another one is equally reachable within the time windows
            if np.abs(their_arrival_times[i] - arrival_times[i]) < np.minimum(time_windows[i][1] - arrival_times[i], time_windows[i][1] - their_arrival_times[i]):
                collaborative_cost[i] += 5  # Added cost if trucks overlap in choices causing possible wait times

    # Compute total costs
    overall_cost = travel_times + time_cost + collaborative_cost
    best_node = np.argmin(overall_cost)

    return best_node
